-- Enrichment marathon batch: Captivate, CaptivateIQ, Carbonite, Carepatron, Carrd, CasaOS, Casbin, Casdoor

-- ── Captivate ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Captivate is a podcast hosting, analytics, and monetization platform offering unlimited storage, IAB-certified analytics, and creator tools starting at $19/month.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19/month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Sheffield, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Captivate Review: Podcast Hosting Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Captivate.fm podcast hosting review: pricing plans, IAB-certified analytics, monetization tools, and creator features. Plans start at $19/month.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Captivate (Captivate.fm) is a podcast hosting and monetization platform founded in January 2019 by Mark Asquith and Kieran McKeefery in Sheffield, United Kingdom. In December 2021, UK media company Global (Global Media & Entertainment, owner of Capital, Heart, Classic FM, and LBC) acquired Captivate, folding the podcast-hosting startup into its portfolio while keeping it running as a standalone platform for independent podcasters. Captivate hosts podcast audio files, generates RSS feeds, and distributes episodes to Apple Podcasts, Spotify, and other listening apps, while providing IAB-certified analytics that meet the Interactive Advertising Bureau's measurement standard used by advertisers to buy podcast ad inventory. The platform runs on three paid plans — Personal at $19/month ($204/year) for up to 30,000 monthly downloads, Professional at $49/month ($528/year) for up to 150,000 monthly downloads, and Business at $99/month ($1,080/year) for up to 300,000 monthly downloads — with every plan receiving the identical full feature set; the only difference between tiers is the monthly download allowance. All plans include a 30-day free trial and unlimited storage, so creators are never charged extra for uploading more episodes, only for downloads beyond their plan's cap. Distinctive features include dynamic ad insertion, which lets ads be swapped into older episodes without re-uploading audio; a built-in podcast website generated automatically for each show; guest booking and scheduling tools; and private podcasting for members-only or internal audio feeds. Captivate bundles what it calls the Captivate Creator Suite into every plan at no extra cost: email opt-in forms for building a listener mailing list, membership and tipping tools for direct listener monetization, and AI-assisted show notes generation. The platform also offers Podcast Growth Labs, an education resource aimed at helping hosts grow audience and revenue. Analytics on every plan include performance comparison across episodes, listener location/device/app breakdowns, unique listener counts for measuring retention, and web player consumption analytics. Captivate exposes a public REST API (documented at docs.captivate.fm) that lets developers authenticate, manage shows and RSS feeds, create and update episodes, upload media, and pull analytics data, plus webhook support for automation. Captivate positions itself against competitors like Buzzsprout, Libsyn, and Podbean by not gating core features behind higher tiers — the download cap is the only lever, which simplifies plan selection as a show's audience grows. Because Captivate has no permanently free plan (only a 30-day trial), it best suits podcasters already committed to publishing regularly rather than casual hobbyists testing the medium. The service covers the full podcast production and monetization lifecycle short of audio editing itself: hosting, distribution, analytics, ad monetization, and audience growth tools. Its ownership by a major European radio and media group also gives it potential access to Global's advertiser relationships for ad monetization, differentiating it from independently owned hosting platforms. Captivate is delivered as a web application with a browser-based dashboard rather than a native desktop or mobile app.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63';

