-- ── Carbonite ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Carbonite is a cloud backup service, now part of OpenText, offering unlimited automatic backup for individuals and businesses with encryption and file versioning.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$4.91/month (billed annually)$q$, starting_price),
  founded_year = COALESCE(2005, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Boston, Massachusetts, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Carbonite Review: Cloud Backup Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Carbonite cloud backup pricing, plans, and features for home and business users, including unlimited storage, encryption, and automatic backup by OpenText.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Carbonite is a cloud backup service founded in 2005 and headquartered in Boston, Massachusetts. In November 2019, enterprise information management company OpenText announced its acquisition of Carbonite for approximately $1.42–1.45 billion (about $23.00 per share), and the deal closed in December 2019, making Carbonite a wholly owned subsidiary within OpenText's cloud-based data protection, backup, disaster recovery, and endpoint security portfolio. Carbonite serves two main markets: personal/home users and small-to-midsize businesses. On the personal side, Carbonite Safe offers unlimited cloud storage for a single computer, with tiers differentiated mainly by add-on capabilities rather than storage caps — Safe Basic covers automatic backup of one computer, Safe Plus adds backup of one external hard drive, and Safe Prime adds video backup and access to Carbonite's Courier Recovery Service, a mail-in option where a physical hard drive containing a customer's backed-up data is shipped to them for large-scale restores rather than requiring a slow full download. On the business side, Carbonite Safe Pro/Server plans scale from Core (up to 25 computers, 250 GB base storage) to Power (adds one server, 500 GB base storage) to Ultimate (unlimited servers, 500 GB base storage), with additional storage purchasable in 100 GB increments. Core backup technology includes continuous and scheduled backup options, 256-bit encryption for data in transit and at rest, two-factor authentication for account security, and file versioning that retains the 12 most recent versions of a changed file so users can roll back accidental edits or deletions. Carbonite offers a 15-day free trial with no credit card required, letting prospective customers test backup functionality before subscribing; annual subscriptions are the standard billing model, with list starting prices around $59.99 for a one-year personal plan historically, though current per-month equivalent pricing across aggregator sources places the entry-level Safe Basic personal plan at roughly $4.91–$6.99 per month when billed annually. Carbonite differentiates itself from newer cloud backup entrants through its long operating history (founded in 2005, one of the earliest consumer cloud backup companies), its physical courier recovery option for large-scale restores, and its integration into OpenText's broader enterprise data protection and Microsoft 365 backup offerings for business customers. Language support is limited to English. Because personal plans cover only a single device (with optional external drive coverage on higher tiers), Carbonite is best suited to users who want straightforward, unlimited backup of one computer rather than multi-device household coverage, while business tiers are aimed at small IT teams needing to back up a defined number of workstations and servers. As part of OpenText, Carbonite benefits from enterprise-grade infrastructure and security practices, though OpenText does not break out Carbonite-specific employee counts publicly.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '26363614-3d73-4304-99d9-162b41b02814';

