-- ── Carepatron ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Carepatron is an all-in-one practice management platform for health and wellness practitioners, combining scheduling, telehealth, billing, and AI notes.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (paid plans from $29/month)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$~45 employees$q$, company_size),
  headquarters = COALESCE($q$Tauranga, New Zealand$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Carepatron: Practice Management Software Pricing & Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Carepatron is a practice management platform for health and wellness practitioners with scheduling, telehealth, billing, and AI notes. Free plan available.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Carepatron is an all-in-one practice management platform for health and wellness practitioners, founded in 2019 by CEO Jamie Frew and CTO David Pene in Tauranga, New Zealand. The platform officially launched in 2021 with a fuller release in early 2022. Carepatron has raised approximately $5 million in funding from investors including Blackbird Ventures and TQ Ventures, and reports serving more than 10,000 healthcare teams and over 100,000 clinicians across 120+ countries, with its interface translated into roughly 24 languages. The company employs an estimated 40–50 people, a lean team relative to its stated user base. Carepatron's product consolidates several functions that many clinics otherwise buy as separate tools: appointment scheduling with automated reminders, telehealth video consultations, a client-facing patient portal, clinical documentation and customizable care plan/note templates, billing and invoicing, and an AI-powered medical scribe that transcribes and structures session notes automatically. The platform is positioned for solo practitioners and small-to-midsize health and wellness practices — including therapists, counselors, physical therapists, and other allied health professionals — rather than large hospital systems. Security and compliance are emphasized throughout the product: Carepatron states it maintains end-to-end encryption, SOC 2 certification, GDPR compliance for international/EU clients, and HIPAA compliance for US healthcare data by default across its plans. Pricing follows a freemium model. The Free plan provides core scheduling, telehealth, and documentation functionality suited to solo or very small practices at no cost. Paid tiers are Essential at $29/month, Plus at $39/month, and Advanced at $49/month, each progressively adding capacity such as unlimited storage, deeper AI workflow automation, custom branding, group scheduling, and analytics; some sources cite an Organization-level enterprise tier priced around $1,990/month for larger, multi-location organizations needing custom configuration and dedicated support, though enterprise pricing is generally quote-based rather than fixed. Carepatron ships with native iOS and Android mobile apps in addition to its web application, letting practitioners manage scheduling and documentation from mobile devices. Competitors in the practice management and EHR space include SimplePractice, TherapyNotes, and Practice Fusion; Carepatron differentiates primarily through its free entry tier, bundled AI scribe functionality even at lower price points, and broad international/multi-language support, positioning it as an accessible option for practitioners and small clinics that find legacy EHR systems costly or complex to adopt. As a company founded in 2019 and only broadly launched in 2021–2022, Carepatron is younger than many established EHR and practice management vendors, though its combination of compliance certifications, AI features, and free-tier accessibility has helped it grow quickly within the allied health and wellness segment.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff4be8dd-9512-4070-826b-f8b412c8fa01';

