-- ── Carrd ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Carrd is a simple, free-to-start builder for responsive one-page websites, with paid Pro plans starting at just $9/year for extra sites and features.$q$, short_description),
  pricing_model = COALESCE($q$Freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free (Pro plans from $9/year)$q$, starting_price),
  founded_year = COALESCE(2016, founded_year),
  company_size = COALESCE($q$2-person team$q$, company_size),
  headquarters = COALESCE($q$Nashville, Tennessee, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Carrd Review: One-Page Website Builder & Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Carrd is a simple one-page website builder with drag-and-drop editing and responsive design. Free plan available; Pro plans start at $9/year.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Carrd is a website builder specialized in simple, responsive one-page sites, created by a solo developer known online as AJ, who is based in Nashville, Tennessee. AJ originally conceived the idea in 2015 as an offshoot of his freelance web design and template work; he publicly launched Carrd via Twitter on March 7, 2016, followed by a Product Hunt launch on March 16, 2016, which drove its early growth. Unlike most website builders, Carrd requires no account to start building — users can drag, drop, and edit a live site directly in the browser, and only need to create an account when they're ready to publish, which effectively turns the product into its own demo. The tool is deliberately narrow in scope: it is built for single-page sites such as portfolios, landing pages, link-in-bio pages, and pre-launch pages, rather than full multi-page websites, blogs, or e-commerce stores. Every Carrd site is responsive by default, automatically resizing and restacking content for phones, tablets, and desktops without additional configuration. The product supports embedding third-party widgets and services, including Stripe and PayPal for payments, Typeform for forms, and Mailchimp and Google Analytics for marketing and tracking, letting a one-page site handle transactional and lead-generation tasks despite its simplicity. Carrd's pricing is notable for being both freemium and extremely inexpensive: the Free tier allows up to 3 sites with Carrd branding and core building tools, while paid Pro tiers are billed annually rather than monthly — Pro Lite at $9/year, Pro Standard at $19/year (adding custom forms, Google Analytics integration, and more widget embeds), and Pro Plus at $49/year (adding password protection, file download functionality, and support for up to 25 sites). This pricing strategy, combined with word-of-mouth and Product Hunt-driven growth, helped Carrd scale to what the founder has described as over 800,000 users and more than 1.2 to 4 million sites built on the platform, generating six-figure monthly recurring revenue while operated by a team of essentially two people — AJ and a collaborator — rather than a venture-backed startup. Carrd is frequently used by indie developers, designers, and small businesses that need a fast, credible web presence without hiring a developer or learning a page builder with a steep learning curve like WordPress or Webflow. Its constraints — single-page format, limited customization ceiling relative to code-based builders, and a small support team — are the tradeoff for its speed, affordability, and simplicity. Language support is English, and there is no native mobile app; Carrd is a web-based, browser-first tool for both building and viewing sites.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5799f1ce-5e51-44c3-9992-d68250deeb71';

