-- ── CasaOS ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CasaOS is a free, open-source personal cloud operating system with a one-click app store, letting anyone turn a Raspberry Pi or old PC into a home server.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Shanghai, China$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$CasaOS: Open-Source Personal Cloud Server Software$q$, seo_title),
  seo_meta_description = COALESCE($q$CasaOS is a free, open-source personal cloud OS with a one-click app store for Nextcloud, Jellyfin, Home Assistant, and more. Runs on Raspberry Pi to x86.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CasaOS is a free, open-source personal cloud operating system originally developed by IceWhale Technology, a company founded in 2020 and based in Shanghai, China, with additional operations noted in Hong Kong and Shenzhen. CasaOS was created as the software layer for ZimaBoard, a crowdfunded x86 single-board server that IceWhale launched on Kickstarter; the OS was subsequently released as its own open-source project and has since grown independently of the hardware, running on a wide range of devices from a $35 Raspberry Pi up to repurposed laptops and dedicated servers. The project is hosted on GitHub under the IceWhaleTech organization and has accumulated more than 33,000 GitHub stars, making it one of the most popular home-server dashboard projects by that measure, alongside competitors like Umbrel, TrueNAS, and OpenMediaVault. CasaOS is not itself an operating system installed from scratch; it runs on top of an existing Linux installation such as Ubuntu, Debian, or Raspberry Pi OS, layering a clean, modern web-based dashboard over the underlying system for managing apps, files, and storage. Its defining feature is a one-click app store containing 100-plus community-curated applications — including Nextcloud for file sync, Jellyfin for media streaming, Home Assistant for home automation, Gitea for self-hosted git repositories, and AdGuard for network-wide ad blocking — each packaged as a standardized 'CasaOS app' combining a JSON manifest with a Docker Compose definition. Under the hood, a Go-based service called CasaOS-AppManagement translates dashboard clicks into `docker compose up` commands, meaning every installed application runs in its own isolated Docker container. Beyond the app store, CasaOS provides a built-in web file browser for navigating and managing files without SSH access, and storage management tools that visualize disk usage and let users mount external drives directly from the dashboard. Because it is fully open-source and free, CasaOS has no pricing tiers, subscriptions, or paid features; it is licensed for self-hosted deployment by individuals or organizations comfortable managing their own Linux server. Development is community-driven, with IceWhale Technology maintaining the core project while community contributors add and maintain individual app store entries and translations. IceWhale has separately developed ZimaOS, a more complete personal-cloud operating system evolved from CasaOS and built on a Debian base, positioned as a fuller alternative for users of Zima-brand hardware, though CasaOS itself remains the free, community-oriented project runnable on virtually any 64-bit Linux machine. CasaOS's target audience is home-lab enthusiasts, self-hosting hobbyists, and small teams who want an approachable, low-cost alternative to commercial NAS software or cloud storage subscriptions, trading the convenience of a managed service for full control over their own hardware and data.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c2436cfe-e0aa-468d-9855-6acb47cd220e';

