-- ── Casbin ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Casbin is a free, open-source authorization library that supports ACL, RBAC, and ABAC access control models across Go, Python, Java, Node.js, and more.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Casbin: Open-Source Authorization Library (ACL/RBAC)$q$, seo_title),
  seo_meta_description = COALESCE($q$Casbin is an open-source access control library supporting ACL, RBAC, and ABAC models across Go, Python, Java, Node.js, and other languages. Free to use.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Casbin is an open-source authorization and access control library originally created in 2017 by Yang Luo, then a student at Peking University, and now maintained as an incubating project under the Apache Software Foundation (Apache Casbin, incubating). Rather than being a hosted service, Casbin is a code library that developers embed directly into their applications to handle permission checks, and it is distributed under the Apache 2.0 license at no cost. Its core idea is the PERM metamodel (Policy, Effect, Request, Matchers), which abstracts an access control model into a human-readable `.conf` configuration file. This lets a development team switch between access control paradigms — Access Control Lists (ACL), Role-Based Access Control (RBAC), Attribute-Based Access Control (ABAC), or combinations like RBAC with domains/tenants — by editing a model definition rather than rewriting application authorization logic. Policies (the actual rules, such as which role can access which resource) are stored separately from the model and can be loaded from files, relational or NoSQL databases, or custom adapters, and updated at runtime through Casbin's API without restarting the application. Casbin's runtime API supports common permission-management operations such as checking whether a given request is permitted, listing all roles assigned to a user, and adding or removing policies dynamically, which makes it suitable for applications that need to manage permissions programmatically rather than through static configuration alone. What distinguishes Casbin from many authorization libraries is its breadth of language support: the core implementation is in Go, with actively maintained ports for Python (pycasbin), Java (jCasbin), Node.js/JavaScript (node-casbin), .NET/C# (Casbin.NET), Rust (casbin-rs), Ruby, C/C++, and PHP, all published under the Apache organization on GitHub. This multi-language consistency allows organizations with polyglot codebases to apply the same access-control model and policy files across services written in different languages. The main Casbin repository has grown to more than 20,000 GitHub stars, reflecting broad production adoption across internet companies, SaaS products, and internal enterprise platforms. Casbin has no pricing or commercial tiers of its own since it is purely an open-source library; organizations that want a full identity and access management (IAM) product with a user interface, rather than just an authorization library, typically pair Casbin with a companion project such as Casdoor, which was built by the same original creator and uses Casbin as its underlying policy engine. Casbin is best suited for developers and platform teams who need fine-grained, model-flexible authorization logic embedded directly into an application or microservice, rather than teams looking for an out-of-the-box, UI-driven access management product.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '05c2f6b8-9698-410f-a6a2-b3cdf7f98777';

