-- ── Casdoor ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Casdoor is a free, open-source identity and access management (IAM) and SSO server supporting OAuth 2.0, OIDC, SAML, LDAP, WebAuthn, and MFA, self-hosted.$q$, short_description),
  pricing_model = COALESCE($q$Free/Open-source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$Casdoor: Open-Source Identity & Access Management (IAM)$q$, seo_title),
  seo_meta_description = COALESCE($q$Casdoor is a free, open-source IAM and SSO platform with a web UI, supporting OAuth 2.0, OIDC, SAML, LDAP, WebAuthn, and MFA for self-hosted deployment.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Casdoor is an open-source identity and access management (IAM) and single sign-on (SSO) platform created by Yang Luo, the same developer behind the Casbin authorization library, with the project originating around 2020 under the Casbin GitHub organization before being spun out into its own dedicated casdoor organization. It is licensed under Apache 2.0 and designed to be self-hosted, giving organizations a UI-first alternative to commercial identity providers such as Okta or Auth0. Unlike reverse-proxy-centric auth tools, Casdoor runs as a dedicated authentication and authorization server with a full web-based admin console for managing users, organizations, applications, and identity providers, rather than only sitting in front of existing services as a gatekeeper. Its protocol support is unusually broad for a single self-hosted project: OAuth 2.0, OpenID Connect (OIDC), SAML, CAS, LDAP, SCIM, WebAuthn, TOTP-based multi-factor authentication, and biometric options like Face ID, alongside integrations with more than 100 third-party identity providers, including Google, Azure AD/Entra ID, GitHub, and Google Workspace. Because Casdoor was built by Casbin's creator, it integrates natively with Casbin as its underlying authorization engine, letting administrators express fine-grained access policies (RBAC, ABAC, and more) on top of the authentication layer that Casdoor provides, rather than requiring a separate authorization system to be bolted on. As of 2026 the project has continued evolving toward supporting authentication for AI agents and tools, adding native Model Context Protocol (MCP) server support and OAuth 2.1 flows aimed at securing AI-agent-to-service authentication, positioning Casdoor as one of the first open-source IAM platforms to explicitly target agentic AI use cases in addition to traditional human user SSO. The main Casdoor repository has accumulated more than 11,000 GitHub stars. As with other self-hosted open-source infrastructure, Casdoor has no pricing tiers or subscription plans; it is free to deploy, and organizations bear only their own hosting and operational costs. It is typically compared against other self-hosted or open-source IAM options such as Keycloak, Authentik, and Zitadel, with Casdoor's main differentiators being its combined breadth of protocol support in a single binary, its UI-first admin experience, and its tight coupling with Casbin's authorization engine. Casdoor is best suited to engineering and platform teams that want to self-host SSO/IAM rather than pay for a commercial identity provider, and that are comfortable taking on the operational responsibility of running and securing an authentication server themselves, including applying updates and managing uptime, since there is no vendor SLA behind the free, community-maintained project.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '698be4be-d4e5-4e9b-8413-12a637e83e7c';

