INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$IAB-Certified Analytics$q$, $q$Download and listener analytics that meet Interactive Advertising Bureau measurement standards, used by advertisers to value podcast ad inventory.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Dynamic Ad Insertion$q$, $q$Swap ads into current and back-catalog episodes without re-uploading audio files.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Built-in Podcast Website$q$, $q$An automatically generated, customizable website for each show, included on every plan.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Guest Booking & Scheduling$q$, $q$Tools for coordinating interview guests and managing recording schedules from within the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Private Podcasting$q$, $q$Members-only or internal audio feeds for gated or non-public content.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Captivate Creator Suite$q$, $q$Bundled email opt-in forms, membership/tipping monetization, and AI-assisted show notes generation included free on all plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Unlimited Storage$q$, $q$No storage caps on any plan; billing is based only on monthly downloads.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Public API & Webhooks$q$, $q$REST API for managing shows, episodes, media, and analytics programmatically, plus webhook support for automation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$No feature gating between tiers — every plan gets the same full toolset$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Unlimited storage regardless of plan$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$IAB-certified analytics included even on the entry-level plan$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Built-in monetization tools (ads, memberships, tipping) without third-party add-ons$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$30-day free trial with full feature access$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$No permanently free plan, only a time-limited trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Pricing scales with monthly downloads, so fast-growing shows must upgrade tiers$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Fewer native mobile apps compared to some larger competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Dynamic ad monetization and sponsorship opportunities depend on reaching sufficient listener volume$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$How much does Captivate cost?$q$, $q$Captivate has three paid plans: Personal at $19/month (up to 30,000 monthly downloads), Professional at $49/month (up to 150,000 monthly downloads), and Business at $99/month (up to 300,000 monthly downloads). Annual billing is also available at a discount.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Does Captivate have a free plan?$q$, $q$Captivate does not offer a permanently free plan, but every paid plan includes a 30-day free trial with full feature access and no credit card charge until the trial ends.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Is storage limited on Captivate?$q$, $q$No. Storage is unlimited on every plan; Captivate bills based on monthly downloads rather than the amount of audio uploaded.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Who owns Captivate?$q$, $q$Captivate was founded independently in 2019 and acquired by Global (Global Media & Entertainment), a major UK radio and media company, in December 2021.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Does Captivate offer an API?$q$, $q$Yes. Captivate provides a public REST API and webhook support for managing shows, episodes, media uploads, and analytics data programmatically.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Can I monetize my podcast on Captivate?$q$, $q$Yes. Captivate includes dynamic ad insertion, listener memberships, and tipping tools on every plan as part of its bundled Creator Suite.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Independent podcast hosting$q$, $q$Hosting, RSS distribution, and IAB-certified analytics for shows publishing regularly across major listening apps.$q$, $q$Independent podcasters and small podcast networks$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Podcast monetization$q$, $q$Dynamic ad insertion, listener memberships, and tipping to generate revenue directly from an existing audience.$q$, $q$Podcasters seeking to monetize an established show$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Private and internal podcasting$q$, $q$Gated, members-only or internal-only audio feeds for training, community, or subscriber content.$q$, $q$Businesses and creators running private audio feeds$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Personal$q$, $q$$19/month$q$, $q$monthly (annual: $204/year)$q$, NULL, $q$["Up to 30,000 monthly downloads","Unlimited storage","IAB-certified analytics","Dynamic ad insertion","Captivate Creator Suite"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Professional$q$, $q$$49/month$q$, $q$monthly (annual: $528/year)$q$, NULL, $q$["Up to 150,000 monthly downloads","Unlimited storage","Full feature set","Captivate Creator Suite"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$Business$q$, $q$$99/month$q$, $q$monthly (annual: $1,080/year)$q$, NULL, $q$["Up to 300,000 monthly downloads","Unlimited storage","Full feature set","Captivate Creator Suite"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Captivate is a podcast hosting, analytics, and monetization platform founded in 2019 by Mark Asquith and Kieran McKeefery in Sheffield, United Kingdom. It was acquired by UK media group Global in December 2021 and continues to operate as a dedicated platform for independent podcasters rather than being merged into Global's own broadcast properties.$q$, $q$The platform handles the core mechanics of podcasting — audio hosting, RSS feed generation, and distribution to Apple Podcasts, Spotify, and other apps — while layering on IAB-certified analytics, monetization tooling, and audience growth features that many rival hosts charge extra for or omit entirely.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every Captivate plan includes the same feature set: IAB-certified analytics, dynamic ad insertion, an auto-generated podcast website, guest booking tools, and private/members-only podcast feeds. Plans differ only by monthly download allowance, not by functionality.$q$, $q$The bundled Captivate Creator Suite adds email opt-in forms, listener membership and tipping tools, and AI-assisted show notes generation at no extra cost. A public REST API and webhook support let developers integrate hosting and analytics data into other tools and workflows.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Captivate offers three tiers: Personal at $19/month for up to 30,000 monthly downloads, Professional at $49/month for up to 150,000 monthly downloads, and Business at $99/month for up to 300,000 monthly downloads. Annual billing brings modest savings ($204, $528, and $1,080 per year respectively).$q$, $q$There is no permanently free plan, but every tier includes a 30-day free trial with no feature restrictions, letting creators test the full platform before committing to a subscription.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5d6ffe1c-7b1f-4bcf-ac7d-d949b13cba63', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$No-Code Commission Plan Builder$q$, $q$Visual interface for designing multi-tier commission structures, accelerators, splits, SPIFs, and clawbacks without engineering support.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Real-Time Commission Calculations$q$, $q$Commissions recalculate automatically as underlying deal and CRM data changes.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Rep Commission Statements$q$, $q$Transparent, self-serve statements that show sales reps exactly how their commission was calculated.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Dispute Resolution Workflow$q$, $q$A structured process for reps to flag and resolve commission discrepancies inside the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Forecasting & What-If Modeling$q$, $q$Simulate the cost and impact of proposed commission plan changes before implementation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$CRM & Data Warehouse Integrations$q$, $q$Native connections to Salesforce, HubSpot, NetSuite, and data warehouses such as Snowflake.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Audit Trail$q$, $q$Full history of plan and calculation changes to support compliance and dispute resolution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Approval Workflows$q$, $q$Configurable approval chains for commission plan changes and payout exceptions.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$No-code plan builder reduces dependence on engineering for commission plan changes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Handles complex, multi-tier, multi-plan commission structures$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Strong native integrations with CRM, ERP, and data warehouse systems$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Rep-facing statements and dispute workflow improve payout transparency and trust$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Backed by well-established venture investors, suggesting long-term product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$No public pricing; all contracts require a custom sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Enterprise-oriented implementation can take significant setup time$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Best suited to mid-market/enterprise teams rather than very small sales organizations$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Per-payee pricing can become costly as headcount and plan complexity grow$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$How much does CaptivateIQ cost?$q$, $q$CaptivateIQ does not publish standard pricing. Contracts are custom-quoted, typically priced on a per-payee (per commissioned employee) basis, so cost depends on team size and plan complexity.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Who founded CaptivateIQ?$q$, $q$CaptivateIQ was founded in 2017 by Mark Schopmeyer, Hubert Wong, and Conway Teng, and is headquartered in San Francisco, California.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$What CRMs does CaptivateIQ integrate with?$q$, $q$CaptivateIQ integrates with Salesforce, HubSpot, NetSuite, and data warehouses such as Snowflake, among other revenue systems.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Is CaptivateIQ suitable for small sales teams?$q$, $q$CaptivateIQ is primarily built for mid-market and enterprise revenue teams with more complex commission structures; very small sales teams may find simpler, lower-cost tools more cost-effective.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Does CaptivateIQ require coding to set up commission plans?$q$, $q$No. CaptivateIQ's core feature is a no-code plan builder that lets RevOps and finance teams configure commission structures through a visual interface.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Automating commission calculations$q$, $q$Replacing spreadsheet-based commission tracking with automated, auditable calculations tied to CRM data.$q$, $q$RevOps and Finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Designing complex incentive plans$q$, $q$Building and testing multi-tier, multi-plan commission structures without engineering resources.$q$, $q$Sales operations and compensation planners$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$Resolving commission disputes$q$, $q$Giving sales reps transparent statements and a formal process to flag and resolve pay discrepancies.$q$, $q$Sales reps and sales leadership$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CaptivateIQ is a sales commission management (incentive compensation management) platform founded in 2017 by Mark Schopmeyer, Hubert Wong, and Conway Teng, and headquartered in San Francisco. The company has raised approximately $164.6 million from investors including Sequoia, Accel, and ICONIQ Growth, reaching a $1.25 billion valuation in its 2022 Series C round.$q$, $q$CaptivateIQ replaces spreadsheet-based commission tracking with an automated system for calculating, communicating, and auditing sales commissions, aimed primarily at RevOps, Finance, and Sales leadership at mid-market and enterprise companies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform's signature feature is a no-code commission plan builder that lets non-engineers construct complex multi-tier commission structures, accelerators, and split-credit rules through a visual interface. Real-time calculations, rep-facing commission statements, and a formal dispute resolution workflow give both finance teams and sales reps visibility into how pay is derived.$q$, $q$Forecasting and what-if modeling let admins simulate the cost of proposed plan changes before launch, while integrations with Salesforce, HubSpot, NetSuite, and data warehouses like Snowflake pull deal data automatically. An audit trail tracks every change for compliance and dispute resolution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CaptivateIQ does not publish standard pricing tiers. Contracts are custom-quoted and priced primarily on a per-payee basis, reflecting the enterprise incentive compensation management category where implementation scope, integrations, and payee count all affect cost.$q$, $q$Because pricing is quote-based and scales with the number of commissioned employees, CaptivateIQ is generally positioned for mid-market and enterprise revenue organizations rather than very small sales teams. Prospective customers need to contact CaptivateIQ directly for a quote.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('171030c2-a2f0-41bf-b969-187ee5d4f56b', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Unlimited Storage (Personal)$q$, $q$No cap on backed-up data volume for a single covered computer on personal plans.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Automatic Continuous & Scheduled Backup$q$, $q$Files back up continuously or on a set schedule, with the ability to exclude certain hours of the day.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$256-bit Encryption$q$, $q$Data is encrypted both in transit and at rest to protect backed-up files.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$File Versioning$q$, $q$Retains the 12 most recent versions of a changed file for rollback purposes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Two-Factor Authentication$q$, $q$Optional SMS-based verification code required when logging in from a new device.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Courier Recovery Service$q$, $q$Mail-in physical hard drive recovery option for restoring large volumes of data (Safe Prime and business tiers).$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$External Hard Drive Backup$q$, $q$Backup coverage for one external hard drive in addition to the primary computer (Plus/Prime tiers).$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Server & Microsoft 365 Backup$q$, $q$Business tiers extend coverage to physical/virtual servers and, through OpenText's broader portfolio, Microsoft 365 data.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Unlimited storage on personal plans regardless of data volume$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Long operating history and enterprise backing from OpenText$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Physical courier recovery option for restoring large data sets without a slow download$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$256-bit encryption and two-factor authentication for account security$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Personal plans cover only a single computer by default$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$English-only language support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$File version history is capped at the 12 most recent versions rather than unlimited$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Business/server plans are priced and licensed separately, which can add up at scale$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$How much does Carbonite cost?$q$, $q$Personal plans start at roughly $4.91–$6.99/month when billed annually for the Safe Basic tier, with Plus and Prime tiers costing more for added recovery options. Business Safe Pro plans range from about $24/month to $83/month depending on the number of computers and servers covered.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Is there a free trial for Carbonite?$q$, $q$Yes, Carbonite offers a 15-day free trial that does not require a credit card, allowing users to test backup functionality before subscribing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Who owns Carbonite now?$q$, $q$Carbonite is a wholly owned subsidiary of OpenText, which acquired the company for approximately $1.42–1.45 billion in a deal that closed in December 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Does Carbonite back up more than one computer?$q$, $q$Personal plans cover a single computer, with higher tiers adding coverage for one external hard drive. Business Safe Pro plans support multiple computers and servers depending on tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$How many file versions does Carbonite keep?$q$, $q$Carbonite retains the 12 most recent versions of a changed file, allowing users to restore an earlier version if needed.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Does Carbonite support two-factor authentication?$q$, $q$Yes, Carbonite offers optional SMS-based two-factor authentication when logging in from a new device.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Personal computer backup$q$, $q$Unlimited, automatic backup of a single home computer with optional external drive coverage.$q$, $q$Individuals and families$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Small business workstation and server backup$q$, $q$Backup coverage for a defined number of business computers and servers, with expandable storage.$q$, $q$Small businesses and IT administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Large-scale data recovery$q$, $q$Physical courier recovery service for restoring large volumes of backed-up data without a slow download.$q$, $q$Users recovering from major data loss or hardware failure$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Basic$q$, $q$$4.91/month$q$, $q$billed annually$q$, NULL, $q$["Unlimited storage, single computer","Automatic backup","256-bit encryption"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Plus$q$, $q$$6.99/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Basic","External hard drive backup"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Prime$q$, $q$$8.74/month$q$, $q$billed annually$q$, NULL, $q$["Everything in Plus","Video backup","Courier Recovery Service"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Pro Core$q$, $q$~$24/month$q$, $q$billed annually$q$, NULL, $q$["Up to 25 computers","250 GB base storage"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Pro Power$q$, $q$~$50/month$q$, $q$billed annually$q$, NULL, $q$["Up to 25 computers + 1 server","500 GB base storage"]$q$::jsonb, 4);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$Safe Pro Ultimate$q$, $q$~$83.33/month$q$, $q$billed annually$q$, NULL, $q$["Up to 25 computers + unlimited servers","500 GB base storage"]$q$::jsonb, 5);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Carbonite is a cloud backup service founded in 2005 and headquartered in Boston, Massachusetts. It was one of the earliest consumer-facing cloud backup companies and has since expanded into small-business and server backup. OpenText acquired Carbonite for roughly $1.42–1.45 billion in a deal that closed in December 2019, and it now operates as part of OpenText's cloud data protection and endpoint security portfolio.$q$, $q$Carbonite serves both personal users backing up a single home computer and small businesses backing up workstations and servers, with plans differentiated primarily by device count and add-on recovery options rather than storage limits.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Personal plans provide unlimited storage for one computer, with continuous or scheduled automatic backup, 256-bit encryption, and two-factor authentication for account security. File versioning retains the 12 most recent versions of a file, allowing rollback of accidental changes or deletions.$q$, $q$Higher personal tiers add external hard drive backup and the Courier Recovery Service, a mail-in physical drive option for restoring large amounts of data without a lengthy download. Business plans (Safe Pro) scale from 25-computer coverage up to unlimited servers with 100 GB storage add-on blocks.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('26363614-3d73-4304-99d9-162b41b02814', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Carbonite's personal plans start around $4.91–$6.99 per month when billed annually for Safe Basic, scaling up through Safe Plus and Safe Prime for external drive and courier recovery features. Business Safe Pro/Server plans range from roughly $24/month for Core (25 computers) to $83/month for Ultimate (unlimited servers).$q$, $q$A 15-day free trial with no credit card required is available for prospective customers to test backup functionality before subscribing. Billing is primarily annual, and additional storage for business plans is sold in 100 GB blocks.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26363614-3d73-4304-99d9-162b41b02814', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26363614-3d73-4304-99d9-162b41b02814', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26363614-3d73-4304-99d9-162b41b02814', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('26363614-3d73-4304-99d9-162b41b02814', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Scheduling & Reminders$q$, $q$Appointment booking with automated client reminders to reduce no-shows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Telehealth$q$, $q$Built-in video consultations for remote client sessions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Client Portal$q$, $q$Secure, client-facing portal for intake forms, messaging, and document sharing.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$AI Medical Scribe$q$, $q$AI-generated session notes and documentation to reduce manual charting time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Billing & Invoicing$q$, $q$Integrated invoicing and payment collection tied to appointments and services.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Customizable Templates & Care Plans$q$, $q$Editable clinical note, intake, and care plan templates across specialties.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Compliance Certifications$q$, $q$End-to-end encryption with SOC 2, GDPR, and HIPAA compliance across plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Mobile Apps$q$, $q$Native iOS and Android apps in addition to the web platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Genuinely usable free plan for solo practitioners$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$AI scribe included even on lower-priced tiers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Broad compliance coverage (HIPAA, GDPR, SOC 2) built into the product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Supports practitioners across 120+ countries with multi-language interface$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Consolidates scheduling, billing, telehealth, and documentation into one platform$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Advanced analytics, branding, and automation are reserved for higher-priced tiers$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Enterprise Organization pricing requires a custom quote rather than being published$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Younger company (founded 2019) than many established EHR vendors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Template and feature depth can vary by clinical specialty$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Does Carepatron have a free plan?$q$, $q$Yes, Carepatron offers a free plan with core scheduling, telehealth, and documentation features suited to solo or very small practices.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$How much does Carepatron cost?$q$, $q$Paid plans start at $29/month for the Essential tier, with Plus at $39/month and Advanced at $49/month. An enterprise Organization tier is available with custom, quote-based pricing for larger organizations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Is Carepatron HIPAA compliant?$q$, $q$Yes, Carepatron states it maintains HIPAA compliance for US healthcare data, alongside GDPR compliance and SOC 2 certification.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Does Carepatron include an AI scribe?$q$, $q$Yes, Carepatron includes an AI-powered medical scribe that transcribes and structures clinical session notes automatically.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Who founded Carepatron?$q$, $q$Carepatron was founded in 2019 by CEO Jamie Frew and CTO David Pene in Tauranga, New Zealand.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Does Carepatron have mobile apps?$q$, $q$Yes, Carepatron offers native iOS and Android apps in addition to its web-based platform.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Solo practice management$q$, $q$Scheduling, telehealth, billing, and documentation for a single practitioner using the free or entry-level paid plan.$q$, $q$Solo therapists, counselors, and allied health practitioners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Multi-practitioner clinic operations$q$, $q$Group scheduling, custom branding, and analytics for growing clinics with multiple providers.$q$, $q$Small-to-midsize health and wellness clinics$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Compliant clinical documentation$q$, $q$HIPAA/GDPR-compliant note-taking and care plans with AI-assisted transcription.$q$, $q$Healthcare teams needing regulatory-compliant records$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, NULL, $q$["Core scheduling","Telehealth","Basic documentation"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Essential$q$, $q$$29/month$q$, $q$monthly$q$, NULL, $q$["Expanded scheduling","Billing & invoicing","AI notes"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Plus$q$, $q$$39/month$q$, $q$monthly$q$, NULL, $q$["Unlimited storage","Custom workflows","Branding"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Advanced$q$, $q$$49/month$q$, $q$monthly$q$, NULL, $q$["Group scheduling","Analytics","Advanced AI workflows"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$Organization$q$, $q$Custom$q$, $q$custom$q$, NULL, $q$["Dedicated support","Custom configuration","Enterprise-scale deployment"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Carepatron is a practice management platform for health and wellness practitioners, founded in 2019 by Jamie Frew (CEO) and David Pene (CTO) in Tauranga, New Zealand. It launched publicly in 2021 with a fuller release in early 2022 and has since grown to serve more than 10,000 healthcare teams and 100,000+ clinicians across over 120 countries.$q$, $q$The platform consolidates scheduling, telehealth, documentation, billing, and an AI-powered clinical scribe into a single product, aiming to replace the patchwork of separate tools that many small practices otherwise rely on.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core functionality includes appointment scheduling with automated reminders, telehealth video consultations, a client-facing patient portal, and customizable clinical documentation and care plan templates. An AI medical scribe transcribes and structures session notes, reducing manual documentation time.$q$, $q$Carepatron emphasizes compliance and security, citing end-to-end encryption, SOC 2 certification, GDPR compliance, and HIPAA adherence across its plans, along with native iOS and Android mobile apps alongside the web application.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Carepatron offers a free plan covering core scheduling, telehealth, and documentation for solo or very small practices. Paid tiers are Essential at $29/month, Plus at $39/month, and Advanced at $49/month, adding unlimited storage, deeper AI workflow automation, custom branding, group scheduling, and analytics.$q$, $q$Larger organizations needing custom configuration and dedicated support can access an enterprise-level Organization plan, which is generally quote-based rather than fixed-price.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ff4be8dd-9512-4070-826b-f8b412c8fa01', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
