INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$No-Account Live Editing$q$, $q$Build and preview a site directly in the browser with no signup required until publishing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Responsive-by-Default Design$q$, $q$Sites automatically adapt to phone, tablet, and desktop screen sizes without extra configuration.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Drag-and-Drop Editor$q$, $q$Simple visual editing for building a one-page site without writing code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Third-Party Widget Embeds$q$, $q$Support for Stripe, PayPal, Typeform, Mailchimp, and Google Analytics embeds.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Custom Domains$q$, $q$Connect a custom domain to a published Carrd site.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Template Gallery$q$, $q$Starter templates for portfolios, landing pages, and link-in-bio pages.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Password Protection & Downloads$q$, $q$Gate pages behind a password and offer file downloads (Pro Plus tier).$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Extremely affordable annual pricing starting at $9/year$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$No account needed to start building — the editor itself is the demo$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Responsive design out of the box with no extra setup$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Very fast to launch a simple, credible web presence$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Large community and template ecosystem despite the tiny team behind it$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Limited to one-page/simple sites, not suited for multi-page or complex sites$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Fewer built-in blogging and e-commerce features than full website builders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Customization ceiling is lower than code-based site builders$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Support is limited given the very small team running the product$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Is Carrd free to use?$q$, $q$Yes, Carrd's Free plan allows up to 3 sites with core building tools. Paid Pro tiers, starting at $9/year, add more sites and features like custom forms and password protection.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Who created Carrd?$q$, $q$Carrd was created by a solo developer known online as AJ, based in Nashville, Tennessee, who launched it publicly in March 2016.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Can I build a multi-page website with Carrd?$q$, $q$No, Carrd is purpose-built for single-page sites such as portfolios, landing pages, and link-in-bio pages rather than full multi-page websites.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Do Carrd sites work on mobile?$q$, $q$Yes, every Carrd site is responsive by default and automatically adapts its layout for phones, tablets, and desktops.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Does Carrd support payments and forms?$q$, $q$Yes, Carrd supports embedding third-party services like Stripe and PayPal for payments and Typeform for custom forms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$How is Carrd priced?$q$, $q$Carrd uses annual billing: Free (3 sites), Pro Lite at $9/year, Pro Standard at $19/year, and Pro Plus at $49/year (up to 25 sites).$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Personal portfolios and landing pages$q$, $q$Fast, responsive one-page sites for individuals showcasing work or a single offer.$q$, $q$Freelancers, designers, and indie creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pre-launch and link-in-bio pages$q$, $q$Simple pre-launch pages for upcoming products and link-in-bio pages for social profiles.$q$, $q$Startups, indie hackers, and social media creators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Small business web presence$q$, $q$A quick, affordable web presence for businesses that need a single credible page rather than a full site.$q$, $q$Small businesses and solo professionals$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Free$q$, $q$$0$q$, $q$n/a$q$, NULL, $q$["Up to 3 sites","Core building tools","Carrd branding"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pro Lite$q$, $q$$9/year$q$, $q$annual$q$, NULL, $q$["Custom domain","No Carrd branding","Basic widgets"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pro Standard$q$, $q$$19/year$q$, $q$annual$q$, NULL, $q$["Custom forms","Google Analytics","More widget embeds"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$Pro Plus$q$, $q$$49/year$q$, $q$annual$q$, NULL, $q$["Password protection","File downloads","Up to 25 sites"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Carrd is a website builder focused exclusively on simple, responsive one-page sites. It was created by a solo developer known as AJ, based in Nashville, Tennessee, who conceived the idea in 2015 and launched it publicly via Twitter and Product Hunt in March 2016.$q$, $q$Unlike most page builders, Carrd requires no account to start: users can build and preview a live site directly in the browser and only sign up when ready to publish. The product has grown into a widely used indie tool, reportedly powering well over a million sites while being run by a team of essentially two people.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every Carrd site is responsive by default, automatically adapting layout for phones, tablets, and desktops. The drag-and-drop editor supports embedding third-party widgets and services, including Stripe and PayPal for payments, Typeform for forms, and Mailchimp and Google Analytics for marketing and tracking.$q$, $q$Higher tiers add custom forms, password-protected pages, file downloads, and support for managing more sites under one account, but the core building experience remains consistent across free and paid tiers.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Carrd's Free plan allows up to 3 sites with core building tools and Carrd branding. Paid Pro tiers are billed annually at notably low prices: Pro Lite at $9/year, Pro Standard at $19/year (adds custom forms, Google Analytics, and more widget embeds), and Pro Plus at $49/year (adds password protection, downloads, and up to 25 sites).$q$, $q$This annual, low-cost pricing model is a deliberate strategy that has helped Carrd achieve broad adoption among indie developers, designers, and small businesses without requiring a large sales or marketing operation.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5799f1ce-5e51-44c3-9992-d68250deeb71', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$One-Click App Store$q$, $q$100+ community apps including Nextcloud, Jellyfin, Home Assistant, and Gitea, installable with a single click.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Docker-Based App Isolation$q$, $q$Every installed app runs in its own Docker container, managed via a Go-based app management service.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Web File Browser$q$, $q$Browse, upload, and manage files through the dashboard without needing SSH access.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Storage Management$q$, $q$Visualize disk usage and mount external drives directly from the web interface.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Broad Hardware Support$q$, $q$Runs on top of Ubuntu, Debian, or Raspberry Pi OS on hardware from a Raspberry Pi to repurposed laptops and servers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Modern Dashboard UI$q$, $q$A clean, consumer-friendly web interface designed to make self-hosting accessible to non-experts.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Completely free and open source with no paid tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Very approachable UI for non-technical self-hosters$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Large, actively maintained one-click app catalog$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Runs on inexpensive hardware, from a Raspberry Pi up$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Large, active GitHub community with frequent updates$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Self-hosted, so users are responsible for their own updates and security$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Smaller app catalog than some larger self-hosting platforms$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Requires an existing Linux installation and basic technical comfort$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Support is community-driven rather than backed by a commercial SLA$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Is CasaOS free?$q$, $q$Yes, CasaOS is fully free and open-source with no paid tiers or subscriptions.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$What hardware does CasaOS run on?$q$, $q$CasaOS runs on top of an existing Linux install and supports hardware ranging from a Raspberry Pi to repurposed laptops, PCs, and dedicated servers, including IceWhale's own ZimaBoard.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Who develops CasaOS?$q$, $q$CasaOS is developed by IceWhale Technology, a company founded in 2020 and based in Shanghai, China, with contributions from an active open-source community.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$What apps can I install with CasaOS?$q$, $q$CasaOS's one-click app store includes over 100 community apps such as Nextcloud, Jellyfin, Home Assistant, Gitea, and AdGuard, each running in its own Docker container.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$How is CasaOS different from ZimaOS?$q$, $q$CasaOS is the free, open-source dashboard project that runs on any compatible Linux machine, while ZimaOS is a more complete Debian-based personal cloud operating system evolved from CasaOS, made by the same company for Zima-brand hardware.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Home lab personal cloud$q$, $q$Turning spare hardware into a personal cloud for file storage, sync, and remote access.$q$, $q$Home-lab enthusiasts and self-hosting hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Self-hosted media and automation server$q$, $q$Running Jellyfin for media streaming and Home Assistant for home automation from one dashboard.$q$, $q$Hobbyists building a home media/automation server$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$Low-cost NAS alternative$q$, $q$Using inexpensive hardware with CasaOS instead of paying for commercial NAS software or cloud storage subscriptions.$q$, $q$Budget-conscious individuals and small teams$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CasaOS is a free, open-source personal cloud operating system developed by IceWhale Technology, a company founded in 2020 and based in Shanghai, China. It originated as the pre-installed software for ZimaBoard, IceWhale's crowdfunded single-board server, before becoming a standalone open-source project that runs on almost any 64-bit Linux machine.$q$, $q$The project is hosted on GitHub under IceWhaleTech and has surpassed 33,000 stars, making it one of the most widely adopted home-server dashboards, alongside alternatives such as Umbrel and OpenMediaVault.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CasaOS runs on top of an existing Linux install (Ubuntu, Debian, Raspberry Pi OS) and provides a modern web dashboard for managing apps, files, and storage. Its one-click app store includes over 100 community-curated apps such as Nextcloud, Jellyfin, Home Assistant, Gitea, and AdGuard, each packaged as a Docker Compose-based 'CasaOS app.'$q$, $q$A built-in web file browser allows file management without needing SSH access, and storage tools visualize disk usage and let users mount external drives directly from the dashboard. Every installed app runs isolated inside its own Docker container.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CasaOS is entirely free and open-source, with no paid tiers, subscriptions, or licensing fees. Users only bear the cost of the hardware they choose to run it on, from a $35 Raspberry Pi to repurposed PCs or dedicated servers.$q$, $q$IceWhale Technology also sells ZimaBoard hardware and maintains ZimaOS, a more fully featured Debian-based personal cloud OS evolved from CasaOS, but CasaOS itself remains free for anyone to install on their own compatible hardware.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c2436cfe-e0aa-468d-9855-6acb47cd220e', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Multiple Access Control Models$q$, $q$Supports ACL, RBAC, ABAC, and hybrid models like RBAC with domains/tenants via a single library.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$PERM Metamodel Configuration$q$, $q$Access control models are defined in human-readable .conf files, decoupled from application code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Multi-Language SDKs$q$, $q$Consistent implementations across Go, Python, Java, Node.js, .NET, Rust, Ruby, C/C++, and PHP.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Runtime Policy Management API$q$, $q$Add, remove, and query permissions and roles dynamically without restarting the application.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Pluggable Policy Storage$q$, $q$Policies can be stored in files or SQL/NoSQL databases through custom adapters.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Role Hierarchy Support$q$, $q$Native support for role inheritance and hierarchical permission structures.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Framework- and language-agnostic authorization model usable across polyglot codebases$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Mature and widely adopted in production, with 20,000+ GitHub stars on the core repository$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Flexible enough to model ACL, RBAC, and ABAC without rewriting application logic$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Backed by Apache Software Foundation incubation for open governance$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Free and open source with no licensing cost$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Requires developers to learn its model/policy configuration syntax$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$No built-in user interface or hosted service on its own$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Documentation depth varies somewhat across the different language SDKs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Fully self-managed, with no vendor support contract available$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Is Casbin free to use?$q$, $q$Yes, Casbin is fully open-source under the Apache 2.0 license and free to use in commercial and non-commercial projects.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$What access control models does Casbin support?$q$, $q$Casbin supports Access Control Lists (ACL), Role-Based Access Control (RBAC), Attribute-Based Access Control (ABAC), and hybrid models such as RBAC with domains, all defined through its PERM metamodel.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Which programming languages does Casbin support?$q$, $q$Casbin's core is written in Go, with actively maintained ports for Python, Java, Node.js/JavaScript, .NET/C#, Rust, Ruby, C/C++, and PHP.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Who created Casbin?$q$, $q$Casbin was created in 2017 by Yang Luo while at Peking University, and is now developed as an incubating project under the Apache Software Foundation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Does Casbin include a user interface?$q$, $q$No, Casbin is a library, not a hosted product with a UI. Projects that need a management interface typically pair it with a companion tool like Casdoor.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Embedding fine-grained authorization$q$, $q$Adding ACL, RBAC, or ABAC permission checks directly into an application without building custom access control logic from scratch.$q$, $q$Application developers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$Standardizing access control across microservices$q$, $q$Applying a consistent authorization model and policy set across services written in different languages.$q$, $q$Platform and infrastructure engineering teams$q$, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Casbin is an open-source authorization library created in 2017 by Yang Luo, then a student at Peking University, and now developed as an incubating project under the Apache Software Foundation. It is distributed free under the Apache 2.0 license and is embedded directly into applications as a code library rather than run as a hosted service.$q$, $q$Its core abstraction, the PERM metamodel, lets developers define an access control model in a configuration file and switch between paradigms like ACL, RBAC, and ABAC without rewriting application logic.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Casbin separates the access control model from the policy data, which can be stored in files, SQL/NoSQL databases, or custom adapters and updated at runtime via API calls. Its runtime API supports permission checks, role queries, and dynamic policy management.$q$, $q$The library is available across many languages — Go (core), Python, Java, Node.js, .NET, Rust, Ruby, C/C++, and PHP — all maintained under the Apache organization on GitHub, letting teams apply a consistent authorization model across polyglot codebases.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Casbin is completely free and open-source under the Apache 2.0 license, with no commercial tiers, subscriptions, or paid support contracts offered by the project itself.$q$, $q$Teams that need a full identity and access management product with a management UI typically pair Casbin with a companion open-source project such as Casdoor, which uses Casbin as its underlying authorization engine.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('05c2f6b8-9698-410f-a6a2-b3cdf7f98777', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Web-Based Admin Console$q$, $q$A UI-first console for managing users, organizations, applications, and identity providers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$OAuth 2.0 & OIDC Provider$q$, $q$Acts as a full OAuth 2.0 and OpenID Connect identity provider for applications.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$SAML, CAS & LDAP Support$q$, $q$Enterprise protocol support for integrating with legacy and corporate directory systems.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$WebAuthn, TOTP & MFA$q$, $q$Passwordless and multi-factor authentication options, including biometric Face ID login.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$100+ Identity Provider Integrations$q$, $q$Pre-built connectors for Google, Azure AD/Entra ID, GitHub, Google Workspace, and more.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Casbin-Powered Authorization$q$, $q$Built-in fine-grained access control (RBAC/ABAC) using Casbin as the underlying policy engine.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$AI Agent Authentication (MCP/OAuth 2.1)$q$, $q$Native Model Context Protocol server support and OAuth 2.1 flows for authenticating AI agents and tools.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Broad protocol support (OAuth, OIDC, SAML, CAS, LDAP) in a single self-hosted deployment$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Tight, native integration with Casbin for fine-grained authorization$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Actively developed, including newer AI-agent authentication support via MCP/OAuth 2.1$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Free and open source under Apache 2.0$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$UI-first design makes administration more approachable than many developer-only IAM tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Self-hosting requires the team to own its own operations and security$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Smaller ecosystem and community than commercial IAM vendors like Okta or Auth0$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$No official vendor support contract or SLA$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Documentation and tooling are geared more toward developers than non-technical admins$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Is Casdoor free?$q$, $q$Yes, Casdoor is free and open-source under the Apache 2.0 license, with no pricing tiers or subscription fees; users only pay for their own hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$What authentication protocols does Casdoor support?$q$, $q$Casdoor supports OAuth 2.0, OpenID Connect (OIDC), SAML, CAS, LDAP, SCIM, WebAuthn, TOTP-based MFA, and Face ID, plus 100+ third-party identity provider integrations.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$How does Casdoor relate to Casbin?$q$, $q$Casdoor was created by the same developer as the Casbin authorization library and uses Casbin natively as its underlying policy engine for fine-grained access control.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Can Casdoor authenticate AI agents?$q$, $q$Yes, Casdoor has added native Model Context Protocol (MCP) server support and OAuth 2.1 flows aimed at authenticating AI agents and tools, in addition to traditional human user SSO.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Is Casdoor a hosted service or self-hosted?$q$, $q$Casdoor is self-hosted; organizations deploy and manage their own instance rather than using a managed cloud service.$q$, 4, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Self-hosted SSO for applications$q$, $q$Replacing paid identity providers like Okta or Auth0 with a self-hosted OAuth/OIDC/SAML server.$q$, $q$Engineering teams wanting to avoid per-user IAM licensing costs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$Fine-grained access control on top of authentication$q$, $q$Combining Casdoor's authentication layer with Casbin's RBAC/ABAC authorization engine for detailed permission management.$q$, $q$Platform teams building internal or customer-facing applications$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$AI agent authentication$q$, $q$Authenticating AI agents and tools via MCP and OAuth 2.1 rather than only human users.$q$, $q$Teams building AI agent or MCP-based integrations$q$, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Casdoor is an open-source identity and access management (IAM) and single sign-on (SSO) platform created around 2020 by Yang Luo, the same developer behind the Casbin authorization library. It began under the Casbin GitHub organization before moving to its own dedicated casdoor organization, and is licensed under Apache 2.0 for free, self-hosted deployment.$q$, $q$Rather than acting only as a reverse-proxy gatekeeper in front of existing apps, Casdoor runs as a dedicated auth server with a full web-based admin console for managing users, organizations, applications, and identity providers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Casdoor supports a broad set of authentication protocols in one self-hosted deployment: OAuth 2.0, OIDC, SAML, CAS, LDAP, SCIM, WebAuthn, TOTP-based MFA, and Face ID, along with integrations for 100+ third-party identity providers including Google, Azure AD, and GitHub.$q$, $q$Because it was built by Casbin's creator, Casdoor integrates natively with Casbin for fine-grained authorization (RBAC, ABAC) on top of authentication. More recent development has added native Model Context Protocol (MCP) server support and OAuth 2.1 flows for authenticating AI agents.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Casdoor is free and open-source with no pricing tiers or subscription plans; it is self-hosted, so the only costs organizations incur are their own hosting and operational overhead.$q$, $q$There is no official vendor support contract or SLA — support comes from the open-source community and project maintainers, similar to other self-hosted IAM tools like Keycloak and Authentik.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('698be4be-d4e5-4e9b-8413-12a637e83e7c', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
